check_cloudflare.code:
def execute():
 import os, json, urllib.request
 token = os.getenv('CLOUDFLARE_API_TOKEN', '')
 if not token:
  return json.dumps({'status': 'error', 'message': '未設定 CLOUDFLARE_API_TOKEN'}, ensure_ascii=False)
 req = urllib.request.Request('https://api.cloudflare.com/client/v4/user/tokens/verify', headers={'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'})
 try:
  resp = urllib.request.urlopen(req, timeout=10)
  data = json.loads(resp.read())
  return json.dumps(data, ensure_ascii=False, indent=2)
 except Exception as e:
  return json.dumps({'status': 'error', 'message': str(e)}, ensure_ascii=False)

