def execute(memory_type='semantic', count=10):
 import json
 from pathlib import Path
 base = Path.home() / '.ampm_brain' / 'memory'
 file_map = {'working': base/'working.json', 'semantic': base/'semantic.json', 'episodic': base/'episodic.json'}
 path = file_map.get(memory_type)
 if not path or not path.exists():
  return f'找不到記憶檔案: {memory_type}'
 data = json.loads(path.read_text())
 if isinstance(data, list):
  items = data[-count:]
  lines = []
  for e in items:
   fact = e.get('fact', e.get('user', ''))[:120]
   imp = e.get('importance', 0)
   lines.append(f'[imp={imp}] {fact}')
  return '\n'.join(lines)
 return str(data)[:2000]
